import { describe, it, expect } from 'vitest';
import {
  validateOrderItems,
  isValidStatusTransition,
  validateStatusTransition,
} from '../../src/validators/order.validator.js';
import type { OrderItem, OrderStatus } from '../../src/models/order.js';

describe('order.validator', () => {
  describe('validateOrderItems', () => {
    it('should accept a non-empty items array', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ];
      expect(() => validateOrderItems(items)).not.toThrow();
    });

    it('should throw for an empty items array', () => {
      expect(() => validateOrderItems([])).toThrow(
        'Order must have at least one item',
      );
    });

    it('should accept multiple items', () => {
      const items: OrderItem[] = [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
      ];
      expect(() => validateOrderItems(items)).not.toThrow();
    });
  });

  describe('isValidStatusTransition', () => {
    const validTransitions: [OrderStatus, OrderStatus][] = [
      ['pending', 'confirmed'],
      ['pending', 'cancelled'],
      ['confirmed', 'shipped'],
      ['confirmed', 'cancelled'],
      ['shipped', 'delivered'],
    ];

    it.each(validTransitions)(
      'should allow %s -> %s',
      (from, to) => {
        expect(isValidStatusTransition(from, to)).toBe(true);
      },
    );

    const invalidTransitions: [OrderStatus, OrderStatus][] = [
      ['pending', 'shipped'],
      ['pending', 'delivered'],
      ['confirmed', 'pending'],
      ['confirmed', 'delivered'],
      ['shipped', 'pending'],
      ['shipped', 'confirmed'],
      ['shipped', 'cancelled'],
      ['delivered', 'pending'],
      ['delivered', 'confirmed'],
      ['delivered', 'shipped'],
      ['delivered', 'cancelled'],
      ['cancelled', 'pending'],
      ['cancelled', 'confirmed'],
      ['cancelled', 'shipped'],
      ['cancelled', 'delivered'],
    ];

    it.each(invalidTransitions)(
      'should reject %s -> %s',
      (from, to) => {
        expect(isValidStatusTransition(from, to)).toBe(false);
      },
    );
  });

  describe('validateStatusTransition', () => {
    it('should not throw for a valid transition', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for an invalid transition with descriptive message', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transitions from terminal states', () => {
      expect(() => validateStatusTransition('delivered', 'shipped')).toThrow(
        'Invalid status transition',
      );
      expect(() => validateStatusTransition('cancelled', 'pending')).toThrow(
        'Invalid status transition',
      );
    });
  });
});
